@typeparam TItem

<div class="infinite-scroll-container" style="overflow-y: auto; max-height: 100%;">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div class="infinite-scroll-sentinel" @ref="_sentinelRef">
            <div class="d-flex justify-content-center py-3">
                <div class="spinner-border" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private ElementReference _sentinelRef;
    private IJSObjectReference? _observer;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? _dotNetRef;
    private bool _isLoading;

    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    [Parameter, EditorRequired]
    public bool HasMore { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    [Parameter, EditorRequired]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    [Inject]
    private IJSRuntime JS { get; set; } = default!;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _observer = await JS.InvokeAsync<IJSObjectReference>(
                "eval",
                """
                (function(sentinel, dotNetRef) {
                    const observer = new IntersectionObserver(entries => {
                        if (entries[0].isIntersecting) {
                            dotNetRef.invokeMethodAsync('OnSentinelVisible');
                        }
                    }, { threshold: 0 });
                    observer.observe(sentinel);
                    return observer;
                })
                """);

            await _observer.InvokeVoidAsync("", _sentinelRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (_isLoading || !HasMore)
            return;

        _isLoading = true;
        await OnLoadMore.InvokeAsync();
        _isLoading = false;
        StateHasChanged();
    }

    public async ValueTask DisposeAsync()
    {
        if (_observer is not null)
        {
            await _observer.InvokeVoidAsync("disconnect");
            await _observer.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }
}

